function unifiedToEthereal(symbol) {
  const parts = symbol.split("/");
  const base = parts[0];
  if (!base) {
    throw new Error(`Invalid symbol format: ${symbol}`);
  }
  const quotePart = parts[1] ?? "";
  const quote = quotePart.split(":")[0] ?? "USD";
  return `${base}-${quote}`;
}
